import sys

def main():
    data = sys.stdin.read().strip().split()
    T = 1
    if data:
        try:
            T = int(data[0])
        except ValueError:
            T = 1
    blocks = []
    for _ in range(T):
        blocks.append('Coding Chef\nChafe\nCoding Chafe')
    sys.stdout.write('\n'.join(blocks))

